final class KeychainHelper {
    static let shared = KeychainHelper()
    private init() {}
    
    func save(_ value: String, for key: String) {
        guard let data = value.data(using: .utf8) else { return }
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
        let attributes: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        SecItemAdd(attributes as CFDictionary, nil)
    }
    
    func load(_ key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var result: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        guard status == errSecSuccess, let data = result as? Data else { return nil }
        return String(data: data, encoding: .utf8)
    }
}

final class APIClient {
    static let shared = APIClient()
    private let session: URLSession
    private let baseURL: URL
    private let tokenKey = "trading.api.token"
    
    private init() {
        let config = URLSessionConfiguration.default
        config.waitsForConnectivity = true
        config.timeoutIntervalForRequest = 15
        config.httpAdditionalHeaders = [
            "Accept": "application/json",
            "Content-Type": "application/json"
        ]
        self.session = URLSession(configuration: config)
        self.baseURL = URL(string: "https://api.yourbrokerage.com/v1")!
    }
    
    var token: String? {
        get { KeychainHelper.shared.load(tokenKey) }
        set {
            if let newValue { KeychainHelper.shared.save(newValue, for: tokenKey) }
        }
    }
    
    func request<T: Decodable>(_ path: String, method: String = "GET", body: Encodable? = nil) async throws -> T {
        let url = baseURL.appendingPathComponent(path)
        var request = URLRequest(url: url)
        request.httpMethod = method
        if let token {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        if let body {
            request.httpBody = try JSONEncoder.api.encode(AnyEncodable(body))
        }
        
        let (data, response) = try await session.data(for: request)
        guard let http = response as? HTTPURLResponse else { throw URLError(.badServerResponse) }
        guard 200..<300 ~= http.statusCode else {
            if let message = try? JSONDecoder.api.decode(ErrorResponse.self, from: data) {
                throw APIError.server(message.message)
            }
            throw APIError.httpStatus(http.statusCode)
        }
        return try JSONDecoder.api.decode(T.self, from: data)
    }
    
    func requestVoid(_ path: String, method: String = "POST", body: Encodable? = nil) async throws {
        let url = baseURL.appendingPathComponent(path)
        var request = URLRequest(url: url)
        request.httpMethod = method
        if let token {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        if let body {
            request.httpBody = try JSONEncoder.api.encode(AnyEncodable(body))
        }
        
        let (data, response) = try await session.data(for: request)
        guard let http = response as? HTTPURLResponse else { throw URLError(.badServerResponse) }
        guard 200..<300 ~= http.statusCode else {
            if let message = try? JSONDecoder.api.decode(ErrorResponse.self, from: data) {
                throw APIError.server(message.message)
            }
            throw APIError.httpStatus(http.statusCode)
        }
    }
}

struct ErrorResponse: Codable {
    let message: String
}

enum APIError: Error, LocalizedError {
    case server(String)
    case httpStatus(Int)
    case invalidPayload
    case insufficientBuyingPower
    case marketClosed
    case unknown
    
    var errorDescription: String? {
        switch self {
        case .server(let message): return message
        case .httpStatus(let code): return "HTTP \(code)"
        case .invalidPayload: return "Invalid payload"
        case .insufficientBuyingPower: return "Insufficient buying power"
        case .marketClosed: return "Market is closed"
        case .unknown: return "Unknown error"
        }
    }
}

struct AnyEncodable: Encodable {
    private let encodeBlock: (Encoder) throws -> Void
    init(_ wrapped: Encodable) {
        self.encodeBlock = wrapped.encode
    }
    func encode(to encoder: Encoder) throws {
        try encodeBlock(encoder)
    }
}

extension JSONEncoder {
    static var api: JSONEncoder {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        return encoder
    }
}

extension JSONDecoder {
    static var api: JSONDecoder {
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        return decoder
    }
}

final class TradingViewModel: ObservableObject {
    @Published var quotes: [StockQuote] = []
    @Published var positions: [Position] = []
    @Published var orders: [TradeOrder] = []
    @Published var account = AccountSummary(cashBalance: 0, buyingPower: 0, totalEquity: 0, dayChange: 0)
    @Published var selectedSymbol: String = "AAPL"
    @Published var quantity: String = "1"
    @Published var limitPrice: String = ""
    @Published var isSubmitting = false
    @Published var alertMessage: String?
    @Published var searchText: String = ""
    
    private var timerCancellable: AnyCancellable?
    private let api = APIClient.shared
    
    init() {
        startRealtimeUpdates()
        Task { await refreshAll() }
    }
    
    func startRealtimeUpdates() {
        timerCancellable?.cancel()
        timerCancellable = Timer.publish(every: 3, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                Task { await self?.refreshQuotes() }
            }
    }
    
    @MainActor
    func refreshAll() async {
        await refreshAccount()
        await refreshPortfolio()
        await refreshQuotes()
        await refreshOrders()
    }
    
    @MainActor
    func refreshQuotes() async {
        do {
            let fetched: [StockQuote] = try await api.request("market/quotes")
            quotes = fetched.sorted { $0.symbol < $1.symbol }
            updatePortfolioPrices(using: fetched)
        } catch {
            if quotes.isEmpty {
                quotes = sampleQuotes()
            }
        }
    }
    
    @MainActor
    func refreshPortfolio() async {
        do {
            let fetched: [Position] = try await api.request("portfolio/positions")
            positions = fetched.sorted { $0.symbol < $1.symbol }
        } catch {
            if positions.isEmpty {
                positions = samplePositions()
            }
        }
    }
    
    @MainActor
    func refreshOrders() async {
        do {
            let fetched: [TradeOrder] = try await api.request("orders")
            orders = fetched.sorted { $0.submittedAt > $1.submittedAt }
        } catch {
            if orders.isEmpty {
                orders = []
            }
        }
    }
    
    @MainActor
    func refreshAccount() async {
        do {
            let summary: AccountSummary = try await api.request("account/summary")
            account = summary
        } catch {
            if account.totalEquity == 0 {
                account = AccountSummary(cashBalance: 25000, buyingPower: 50000, totalEquity: 25000, dayChange: 0)
            }
        }
    }
    
    @MainActor
    func submitOrder(side: TradeSide) async {
        guard !isSubmitting else { return }
        guard let qty = Int(quantity), qty > 0 else {
            alertMessage = "Enter a valid quantity"
            return
        }
        let price = Double(limitPrice.trimmingCharacters(in: .whitespacesAndNewlines))
        isSubmitting = true
        defer { isSubmitting = false }
        
        let order = TradeOrder(
            id: UUID(),
            symbol: selectedSymbol.uppercased(),
            side: side,
            quantity: qty,
            limitPrice: price,
            submittedAt: Date(),
            status: .pending
        )
        
        do {
            try validate(order: order)
            try await api.requestVoid("orders", method: "POST", body: order)
            var filledOrder = order
            filledOrder.status = .filled
            orders.insert(filledOrder, at: 0)
            applyLocalFill(order: filledOrder)
            alertMessage = "\(side.rawValue.capitalized) order submitted"
        } catch {
            alertMessage = error.localizedDescription
        }
    }
    
    private func validate(order: TradeOrder) throws {
        if order.side == .buy {
            let estimatedCost = Double(order.quantity) * (order.limitPrice ?? marketPrice(for: order.symbol))
            if estimatedCost > account.buyingPower {
                throw APIError.insufficientBuyingPower
            }
        }
    }
    
    private func marketPrice(for symbol: String) -> Double {
        quotes.first(where: { $0.symbol == symbol })?.lastPrice
        ?? positions.first(where: { $0.symbol == symbol })?.marketPrice
        ?? 0
    }
    
    private func applyLocalFill(order: TradeOrder) {
        let fillPrice = order.limitPrice ?? marketPrice(for: order.symbol)
        account.cashBalance += order.side == .buy ? -(Double(order.quantity) * fillPrice) : (Double(order.quantity) * fillPrice)
        account.buyingPower = max(0, account.cashBalance * 2)
        account.totalEquity = account.cashBalance + positions.reduce(0) { $0 + $1.marketValue }
        
        if let index = positions.firstIndex(where: { $0.symbol == order.symbol }) {
            var position = positions[index]
            switch order.side {
            case .buy:
                let newQty = position.quantity + order.quantity
                let totalCost = (Double(position.quantity) * position.avgCost) + (Double(order.quantity) * fillPrice)
                position.quantity = newQty
                position.avgCost = newQty > 0 ? totalCost / Double(newQty) : 0
                position.marketPrice = fillPrice
                positions[index] = position
            case .sell:
                position.quantity -= order.quantity
                position.marketPrice = fillPrice
                if position.quantity <= 0 {
                    positions.remove(at: index)
                } else {
                    positions[index] = position
                }
            }
        } else if order.side == .buy {
            positions.append(Position(symbol: order.symbol, quantity: order.quantity, avgCost: fillPrice, marketPrice: fillPrice))
        }
        positions.sort { $0.symbol < $1.symbol }
    }
    
    private func updatePortfolioPrices(using quotes: [StockQuote]) {
        for idx in positions.indices {
            if let quote = quotes.first(where: { $0.symbol == positions[idx].symbol }) {
                positions[idx].marketPrice = quote.lastPrice
            }
        }
        account.totalEquity = account.cashBalance + positions.reduce(0) { $0 + $1.marketValue }
    }
    
    private func sampleQuotes() -> [StockQuote] {
        [
            StockQuote(symbol: "AAPL", name: "Apple Inc.", lastPrice: 187.42, change: 1.24, changePercent: 0.67, bid: 187.40, ask: 187.44, volume: 65234123, updatedAt: Date()),
            StockQuote(symbol: "MSFT", name: "Microsoft Corp.", lastPrice: 412.66, change: -0.88, changePercent: -0.21, bid: 412.62, ask: 412.70, volume: 24123111, updatedAt: Date()),
            StockQuote(symbol: "NVDA", name: "NVIDIA Corp.", lastPrice: 875.12, change: 12.31, changePercent: 1.43, bid: 875.00, ask: 875.22, volume: 35114555, updatedAt: Date()),
            StockQuote(symbol: "TSLA", name: "Tesla Inc.", lastPrice: 226.89, change: -3.40, changePercent: -1.48, bid: 226.84, ask: 226.94, volume: 49221888, updatedAt: Date())
        ]
    }
    
    private func samplePositions() -> [Position] {
        [
            Position(symbol: "AAPL", quantity: 40, avgCost: 178.20, marketPrice: 187.42),
            Position(symbol: "MSFT", quantity: 10, avgCost: 404.10, marketPrice: 412.66)
        ]
    }
}

